# -- Helpers --
import difflib as _difflib
import random as _random
import textwrap as _tw

_LINE_WIDTH = 70


def _norm_answer(s):
    # Fold away the differences that should not matter when matching a typed
    # answer against an option: surrounding whitespace, internal run-length,
    # letter case, and a trailing period.
    return " ".join(s.strip().lower().split()).strip(" .")


def _best_match(raw, options, cutoff=0.82):
    # Resolve a typed answer to one of `options`, forgiving tiny typos. Returns
    # the exact option string (so the caller can decrypt with the canonical
    # value), or None if nothing is close enough.
    norm = {}
    for opt in options:
        norm.setdefault(_norm_answer(opt), opt)
    key = _norm_answer(raw)
    if key in norm:
        return norm[key]
    close = _difflib.get_close_matches(key, list(norm.keys()), n=1, cutoff=cutoff)
    return norm[close[0]] if close else None


def _show_choices(options):
    print("  Choose one (type or paste the exact phrase -- small typos are ok):")
    for opt in options:
        for ln in _tw.wrap(opt, width=_LINE_WIDTH - 6,
                           initial_indent="    - ", subsequent_indent="      "):
            print(ln)

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _wrap(text):
    return _tw.wrap(text, width=_LINE_WIDTH - 4,
                    initial_indent="  ", subsequent_indent="    ")

def _show_wrong(raw, wrong_dict):
    exp = wrong_dict.get(raw)
    if exp:
        print()
        for ln in _wrap(f"[wrong] {exp}"):
            print(ln)
    else:
        print(f"  [wrong] {raw!r} is not the correct answer.")

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)


def _secret_for_item(index):
    """Open the encrypted answer/explanation payload for a 1-based item index."""
    secret = _open_secret(ITEM_SECRETS[index - 1], "wrap-court:question:" + str(index))
    if secret is None:
        print("  [error] Could not open item data -- contact your instructor.")
        sys.exit(1)
    return secret


class ActivityEngine:
    """Core check/passphrase logic for Activity: Wrap Court; importable without a TTY."""

    slug = "wrap-court"
    title = "Activity: Wrap Court"
    description = "Eight questions putting decorators on trial: what @deco desugars to, when a decorator's own code runs versus when its wrapper runs, what happens when a wrapper is never returned, how a parameterized decorator like @retry(3) adds an extra layer of calls, why *args/**kwargs and functools.wraps exist, and what a closure actually is. Explanations build every term (closure, wrapper, decoration) from scratch."

    def items(self):
        """Return the public (non-secret) item dicts, in display order."""
        return QUESTIONS

    def _options(self, index):
        """Shuffled display options (answer + distractors) for a choices item.

        Order is deterministic per item so the correct answer is not always in
        the same position, but is stable across runs.
        """
        secret = _secret_for_item(index)
        opts = [secret["answer"]] + list((secret.get("wrong") or {}).keys())
        _random.Random(self.slug + ":" + str(index)).shuffle(opts)
        return opts

    def check(self, index, raw):
        """Check a 1-based item's raw answer; return {correct, feedback, explanation, canonical}.

        For a concept "choices" item the raw input is matched against the
        displayed options with small-typo tolerance, and `canonical` carries the
        exact answer string to decrypt with; for other items an exact match is
        required and `canonical` is the raw input.
        """
        secret = _secret_for_item(index)
        answer = secret["answer"]
        wrong = secret.get("wrong") or {}
        item = self.items()[index - 1]
        if item.get("choices"):
            matched = _best_match(raw, self._options(index))
            if matched is None:
                return {"correct": False, "feedback": None, "explanation": None, "canonical": raw}
            correct = matched == answer
            return {
                "correct": correct,
                "feedback": None if correct else wrong.get(matched),
                "explanation": secret.get("explanation", "") if correct else None,
                "canonical": answer if correct else matched,
            }
        correct = raw == answer
        return {
            "correct": correct,
            "feedback": None if correct else wrong.get(raw),
            "explanation": secret.get("explanation", "") if correct else None,
            "canonical": raw,
        }

    def passphrase(self, answers):
        """Return the unlocked passphrase once all answers are correct, else None."""
        return _decrypt(_BLOB, answers)


ENGINE = ActivityEngine()


def _ask(item, index, total):
    _hr()
    print(f"\n  Q{index:02}/{total:02}  {item['prompt']}")
    print()
    for line in item.get("code", "").splitlines():
        print(f"    {line}")
    print(f"\n  Hint: {item['hint']}")
    while True:
        raw = input("\n  Your answer: ").strip()
        if not raw:
            continue
        result = ENGINE.check(index, raw)
        if result["correct"]:
            print()
            for ln in _wrap(("Correct.  " if True else "") + result.get("explanation", "")):
                print(ln)
            return raw
        _show_wrong(raw, {raw: result["feedback"]} if result.get("feedback") else {})
        print("  Think about each call separately and try again.")


def main():
    _banner(ENGINE.title)
    print()
    input("  Press Enter to begin...")

    answers = []
    items = ENGINE.items()
    total = len(items)
    for i, item in enumerate(items, 1):
        answers.append(_ask(item, i, total))

    print()
    print("  All correct.")
    passphrase = ENGINE.passphrase(answers)
    if passphrase is None:
        print("  [error] Decryption failed -- contact your instructor.")
        sys.exit(1)
    _show_passphrase(passphrase)


if __name__ == "__main__":
    main()
